window.SDOC_MAP_MID_TO_NODES = {"1":{"MID":"b309888107554ab0b976acd70a721f49","UID":"EL-124","TITLE":"Introduction","_LINK":"EL-124"},"2":{"MID":"cb75f263e7b24c08a6dab3423220c412","STATEMENT":"This document is configured to showcase the\nPDF Export Watermark\nfeature. After selecting\nOperations > Export to PDF,\neach page is watermarked with an image. Rules for document watermarks can also be specified via a plugin. This plugin lets users force watermarks based on a custom field value like \"Restricted documents\".\n\n","_LINK":"cb75f263e7b24c08a6dab3423220c412"},"3":{"MID":"d807ef8f24454956b95ae77afcebb878","UID":"EL-5","TITLE":"Purpose","_LINK":"EL-5"},"4":{"MID":"9f835e5823b849eea0ad652a6653f3b6","STATEMENT":"A Product Specification is a complete description of the behavior of the product to be developed. It includes a set of User Stories that describe all the interactions that users will have with the software. In addition to User Stories, this document also contains Requirements.\n\n","_LINK":"9f835e5823b849eea0ad652a6653f3b6"},"5":{"MID":"8866159d5ae048608fc2ea6b79babaf3","UID":"EL-125","TITLE":"Scope","_LINK":"EL-125"},"6":{"MID":"6a2e7099479b43adb4938e20719af8fa","STATEMENT":"The document describes a fictitious online eBook lending library with an optional online eBook sales component. The focus is on simplicity rather than depth and completeness, so that you may more easily understand the Document's features.\nNot all the User Stories need to be implemented in the 1.0 release.  The release planning is managed separately. See \n.\n\n","_LINK":"6a2e7099479b43adb4938e20719af8fa"},"7":{"MID":"ae25bfccd1de4a8ca6e5a3e3bd1114de","UID":"EL-70","TITLE":"References","_LINK":"EL-70"},"8":{"MID":"efef83d9b85a468eb49a0e7ae013c533","STATEMENT":"Specifications:\n\n","_LINK":"efef83d9b85a468eb49a0e7ae013c533"},"9":{"MID":"35ffe5650e5a4cf188ec75ea451f8d7e","UID":"EL-6","TITLE":"Overall Description","_LINK":"EL-6"},"10":{"MID":"7843270cefd84160a19ec7f9b1d17e18","STATEMENT":"This system provides an online portal analogous to a public library where registered patrons can \"borrow\" books. The main difference being, that the books in the library catalog are all in electronic formats that incorporate Digital Rights Management (DRM). This lets the system “lend” an allowed number of copies to registered users. In addition, when a book has the proper rights, the E-Library can sell patrons a license for a personal copy of the electronic book that they can retain permanently.\n\n","_LINK":"7843270cefd84160a19ec7f9b1d17e18"},"11":{"MID":"fb27eb754e354460a7fd7100963835fb","UID":"EL-7","TITLE":"Abbreviations and Terms","_LINK":"EL-7"},"12":{"MID":"882d1b5c0d6d431c92e2e32cab592bf7","STATEMENT":"\n.. list-table::\n    :widths: 1 1\n    :header-rows: 1\n\n    * - TERM\n      - DEFINITION\n    * - Cart\n      - i.e. “Shopping Cart” – A collection of one or more eBooks that a patron has marked for purchase during the current session.\n    * - Catalog\n      - The database of eBooks available for loan and possibly for sale.\n    * - Check Out\n      -  used in reference to the process of paying for a purchased eBook. (See Purchase.)\n    * - Check In\n      - The act of “returning” a previously “borrowed” (checked out) eBook.\n    * - DRM\n      - Digital Rights Management\n    * - eBook\n      - An electronic book or other publication lent or sold by the E-Library system.\n    * - ISBN\n      - International Standard Book Number\n    * - LC\n      - Library of Congress\n    * - Loan\n      - Lend.\n    * - Lend\n      - The process of flagging an eBook so the appropriate DRM understands that one of the allowable number of “copies” has been allocated to a patron for the allowable lending period.\n    * - Patron\n      - A user of the E-Library portal.\n    * - Purchase\n      - (Also refers to the action of a user navigating through the process of purchasing the eBooks listed in their Cart.)\n    * - Store\n      - (eBooks that users can purchase a personal copy license for.)\n\n","_LINK":"882d1b5c0d6d431c92e2e32cab592bf7"},"13":{"MID":"d6f9f2c9d99d40fb9a91f47aa8accd8d","UID":"EL-112","TITLE":"Product Backlog","_LINK":"EL-112"},"14":{"MID":"f322c3384d9844f88305972c6237c499","UID":"EL-110","TITLE":"Basics","_LINK":"EL-110"},"15":{"MID":"7da75e74c40d4a5d8755e0917d4f6a6f","UID":"EL-198","STATUS":"In Progress","TITLE":"Basic Product Behavior","STATEMENT":"This Epic sums up the basic behavior of the product.\n\n","_LINK":"EL-198"},"16":{"MID":"98876da228a741d48a76eae1c3458f68","UID":"EL-107","STATUS":"Verified","TITLE":"User Statistics","STATEMENT":"Users should easily access information on what books they have borrowed.\n\n","_LINK":"EL-107"},"17":{"MID":"28481480f479463dbd90427918fae21a","UID":"EL-191","STATUS":"Draft","TITLE":"Password Regex","STATEMENT":"The password must fit the specified Requirements.\n\n","_LINK":"EL-191"},"18":{"MID":"28f108a6f9f6432a893cdbb4f38024a3","UID":"EL-105","STATUS":"Verified","TITLE":"Login Page","STATEMENT":"When users want to access the Elibrary portal they need to login and provide valid credentials.\n\n","_LINK":"EL-105"},"19":{"MID":"e826bbfb0de04a6f86cee751cffedf0f","UID":"EL-138","STATUS":"Implemented","TITLE":"Access the list of favorite books","STATEMENT":"Users must be able to easily access their list of \"Favorite\" books.\n\n","_LINK":"EL-138"},"20":{"MID":"09af4ff2a86449809f36c93e789d9cef","UID":"EL-139","STATUS":"In Progress","TITLE":"Maintain the list of favorite books","STATEMENT":"Users should be able to maintain their list of \"Favorite\" books.\n\n","_LINK":"EL-139"},"21":{"MID":"a46c0837146c4dadad55af4a06dda037","UID":"EL-136","STATUS":"In Progress","TITLE":"Configure contact information","STATEMENT":"Users must be able to configure their contact information.\n\n","_LINK":"EL-136"},"22":{"MID":"0c213a5ff06e4b1f95e535c8d593da20","UID":"EL-137","STATUS":"Accepted","TITLE":"Mark a book as favorite","STATEMENT":"Users must be able to mark a book as a \"Favorite\".\n\n","_LINK":"EL-137"},"23":{"MID":"bf385ba68ba34725a1483443052b6610","UID":"EL-140","STATUS":"Verified","TITLE":"Administration","STATEMENT":"Basic users may not be allowed to administer the elibrary system.\n\n","_LINK":"EL-140"},"24":{"MID":"1ff1a7b7b81a45658bcca3c615ccc72c","UID":"EL-113","TITLE":"Book Information","_LINK":"EL-113"},"25":{"MID":"3528220e49d840a98a73c4eb7df216ef","UID":"EL-199","STATUS":"In Progress","TITLE":"Books","STATEMENT":"This Epic describes the Book object.\n\n","_LINK":"EL-199"},"26":{"MID":"67c4edc9858c468da8152723742f295e","UID":"EL-118","STATUS":"Verified","TITLE":"Detailed book information","STATEMENT":"Users want to view additional information about a book:\n\n- Number of pages\n- Who illustrated the book\n- Price\n\n","_LINK":"EL-118"},"27":{"MID":"260c76f7f9cf41e08a6f496ba478a131","UID":"EL-116","STATUS":"Verified","TITLE":"Basic Book Details","STATEMENT":"Users want to view basic information about the book:\n\n- Title\n- Author\n- Published date\n- ISBN\n\n","_LINK":"EL-116"},"28":{"MID":"b1dc48a6ae9d4695aaa228b55d0ae814","UID":"EL-117","STATUS":"Accepted","TITLE":"Summary of the book","STATEMENT":"When viewing book details, users also want to read a book's summary (abstract).\n\n","_LINK":"EL-117"},"29":{"MID":"9587d6bf57ca4910b7eea09d751d6e01","UID":"EL-130","STATUS":"Accepted","TITLE":"Online services","STATEMENT":"Users also want to easily get a list of online resources, with links to Amazon, ReviewMyBook and other online services.\nThis list of services needs to be configurable.\n\n","_LINK":"EL-130"},"30":{"MID":"bf9ece2a5eaa42c59a4a417dc1d221e5","UID":"EL-131","STATUS":"Verified","TITLE":"EBook -  supported readers","STATEMENT":"If the book is an eBook, users must be able to get information about the supported reader applications and platforms.\n\n","_LINK":"EL-131"},"31":{"MID":"97d649aa1e104f10a0aa5fb7908acd92","UID":"EL-114","TITLE":"Author Information","_LINK":"EL-114"},"32":{"MID":"493bd06423c748408096a83c644070eb","UID":"EL-200","STATUS":"In Progress","TITLE":"Author","STATEMENT":"This Epic describes the Author object.\n\n","_LINK":"EL-200"},"33":{"MID":"2b50103cd6b04dc3b1a07cd08dbe6d83","UID":"EL-119","STATUS":"Verified","TITLE":"Basic Author Details","STATEMENT":"When viewing a book's details, users also want to get information about the author or authors. The details should include:\n\n- Full name\n- Date of birth\n- Date of death (If deceased) \n- A list of other books written by them. (If more than 5, the 6th entry can be a link to a complete bibliography page.)\n\n","_LINK":"EL-119"},"34":{"MID":"453f14e11d6644c0bef146d26b3eafb8","UID":"EL-121","STATUS":"Accepted","TITLE":"When viewing an author's list of books, users want to see which books are stored...","STATEMENT":"When viewing an author's list of books, users want to see which books are stored in the library and whether or not they are currently available for check out.\n\n","_LINK":"EL-121"},"35":{"MID":"150d8a3ff9c94e41b11df15c327088d8","UID":"EL-120","STATUS":"Reviewed","TITLE":"Photo of an author","STATEMENT":"Show photo(s) of an author.\n\n","_LINK":"EL-120"},"36":{"MID":"cb32a2e46098415d803d3eacfede85cb","UID":"EL-111","TITLE":"Searches","_LINK":"EL-111"},"37":{"MID":"b30b43dbd394430ea590a79b02be4a66","UID":"EL-201","STATUS":"In Progress","TITLE":"Searches","STATEMENT":"This Epic describes all relevant information for the Search feature.\n\n","_LINK":"EL-201"},"38":{"MID":"2c6ab1cdc7684fa19244a754f19a39b0","UID":"EL-108","STATUS":"Verified","TITLE":"Search for a book by book name","STATEMENT":"Users typicaly search for the book by name. This feature should be accesssible all the times.\n\n","_LINK":"EL-108"},"39":{"MID":"5e296cd26bac43a298a9967c12d56510","UID":"EL-115","STATUS":"Verified","TITLE":"Search for an author by author name","STATEMENT":"Users want to be able to search for authors by name.\n\n","_LINK":"EL-115"},"40":{"MID":"c2d2ef6756f4419d9ea6196317cffa9c","UID":"EL-134","STATUS":"Verified","TITLE":"Listing of the 20 most frequently borrowed eBooks.","STATEMENT":"The system should provide a way to return a list of the 20 most frequently borrowed eBooks.\n\n- The actual number should be configurable by an administrator.\n- The UI should provide a selectable list of values: 10, 20, 25, 50, 100\n\n","_LINK":"EL-134"},"41":{"MID":"d87375ca0f264a8194cd23b109e9c764","UID":"EL-135","STATUS":"Verified","TITLE":"The listing of 10-50 recently checked books.","STATEMENT":"The system should provide an easy way to get the listing of the 10-50 (configurable) most recently checked-in eBooks.\n\n","_LINK":"EL-135"},"42":{"MID":"f3c76c0265b3490495cb44db0c0cd47a","UID":"EL-132","STATUS":"Change Implementation","TITLE":"Advanced Search should provide an easy way to construct complex search queries","STATEMENT":"Advanced Search \nshould provide an easy way to construct complex search queries based on multiple fields with different logic (e.g. AND, OR, NOT).\n\n","_LINK":"EL-132"},"43":{"MID":"af4a41d81a384b56bea8fb88591bc4db","UID":"EL-133","STATUS":"Verified","TITLE":"List of newly added books.","STATEMENT":"The system must provide an easy way to list newly added books. It can return a listing of the 10 - 50 (configurable) most recently added eBooks.\n\n","_LINK":"EL-133"},"44":{"MID":"6a77aa03b3f945b99808b2fd96b5acf9","UID":"EL-122","STATUS":"In Progress","TITLE":"Users like to also search for content - (Full-text search)","STATEMENT":"Users aslo like to search for content. This requires a full-text search option.\n\n","_LINK":"EL-122"},"45":{"MID":"9fc83fa208d646508bfaf57a4b6517c9","UID":"EL-109","STATUS":"In Progress","TITLE":"Search for a book by advanced properties","STATEMENT":"Users want to search for books using additional properties, for example ISBN or date, but this advanced search should not be too complicated.\n\n","_LINK":"EL-109"},"46":{"MID":"f25a4eb9fed04bf0bc64e5bd2b8cd949","UID":"EL-127","TITLE":"Administration","_LINK":"EL-127"},"47":{"MID":"975ecb91d56a41fd81cd8d49778eee49","UID":"EL-141","TITLE":"User Roles","_LINK":"EL-141"},"48":{"MID":"c2083643a82244edbaacd0ae57316553","STATEMENT":"The system must provide for the following types of user accounts:\n\n.. list-table::\n    :widths: 1 1\n    :header-rows: 1\n\n    * - ACCOUNT TYPE\n      - PERMISSIONS\n    * - Administrator\n      - Can access any component or area of the system including the accounts of other users.\n    * - Librarian\n      - Can access the catalog management features of the system.\n    * - Patron\n      - Can access the general library features, including browsing, searching, check out, check in, reserve, and purchase.\n    * - Student\n      - Same as a Patron, except students can not access Purchase features.\n\n","_LINK":"c2083643a82244edbaacd0ae57316553"},"49":{"MID":"8ff106fc638e44cfae7e5161e3069bde","UID":"EL-202","STATUS":"Verified","TITLE":"User Roles","STATEMENT":"This Epic sums up all the information on the User Roles feature.\n\n","_LINK":"EL-202"},"50":{"MID":"48140f9713ec47a19a6dfbd8f07d5592","UID":"EL-143","STATUS":"Verified","TITLE":"System Administrator must be able to set the user roles.","_LINK":"EL-143"},"51":{"MID":"53060f4e0076405794bc6d88d407d0ff","UID":"EL-142","STATUS":"Verified","TITLE":"There are two user roles: Basic User and Administrator.","STATEMENT":"There are two user roles: Basic User and Administrator. Basic users have no access to the administration portal.\n\n","_LINK":"EL-142"},"52":{"MID":"8784b66740d4429fbf6db93921d45f5d","UID":"EL-8","TITLE":"Requirements","_LINK":"EL-8"},"53":{"MID":"88bc328c9c5141589272f7f6cea7561d","UID":"EL-9","TITLE":"Performance Requirements","_LINK":"EL-9"},"54":{"MID":"b5d2835f45c441f584f5495b64134fa6","STATEMENT":"If there are performance requirements for the product under various circumstances, state them here and explain their rationale.This helps developers understand the intended performance targets and make design choices accordingly. Specify the timing relationships for real time systems. Make these requirements as specific as possible. You may need to state performance requirements for individual functional requirements or features.\n\n","_LINK":"b5d2835f45c441f584f5495b64134fa6"},"55":{"MID":"454f5fa7af394025bd38606da4908f57","UID":"EL-69","STATUS":"Rejected","TITLE":"This is a sample of non functional requirement.","_LINK":"EL-69"},"56":{"MID":"8bc842b0b9774f1797630ddbac8dbc70","UID":"EL-10","TITLE":"Safety Requirements","_LINK":"EL-10"},"57":{"MID":"86612a61003b4b3f991917c4ad91363e","STATEMENT":"Specify any requirements concerned with possible loss, damage, or harm that could result from the use of the product. Define any safeguards or actions that must be taken, as well as actions that must be prevented. Refer to any external policies or regulations that describe safety issues that could affect the product’s design or use. Define any safety certifications that must be satisfied.\n\n","_LINK":"86612a61003b4b3f991917c4ad91363e"},"58":{"MID":"9f8713dbb4f64fa4b19335330a0c8a38","UID":"EL-11","TITLE":"Security Requirements","_LINK":"EL-11"},"59":{"MID":"4302ed5ffa534d9f90086bd67dcb7972","STATEMENT":"Specify any requirements regarding security or privacy issues surrounding the use of the product or the protection of data used and created by the product. Define any user identity authentication requirements. Refer to any external policies or regulations containing security issues that affect the product. Define any security or privacy certifications that must be satisfied.\n\n","_LINK":"4302ed5ffa534d9f90086bd67dcb7972"},"60":{"MID":"1c47dbe120a74b9fad852840a6fdabe7","UID":"EL-12","TITLE":"Software Quality Attributes","_LINK":"EL-12"},"61":{"MID":"3c7b5616f7734302a373217f8217aaa9","STATEMENT":"Specify any additional quality characteristics for the product that will be important to either customers or developers. Some to consider are: adaptability, availability, correctness, flexibility, interoperability, maintainability, portability, reliability, reusability, robustness, testability, and usability. Write these to be specific, quantitative, and verifiable when possible. At the very least, clarify the relative preferences for various attributes, such as ease of use over ease of learning.\n\n","_LINK":"3c7b5616f7734302a373217f8217aaa9"},"62":{"MID":"3fffe1da054a47419546acb9ac125b30","UID":"EL-13","TITLE":"Other Requirements","_LINK":"EL-13"},"63":{"MID":"fff14da217e34ce789043fcd43684190","STATEMENT":"Define any other requirements not covered elsewhere in the specification. This might include database requirements, internationalization requirements, legal requirements, reuse objectives for the project, and so on. Add any new sections that are pertinent to the project.\n\n","_LINK":"fff14da217e34ce789043fcd43684190"},"64":{"MID":"49b6ac2b640d495fad99335333468cb7","UID":"EL-128","TITLE":"Appendix A: Terminology/Glossary/Definitions list","_LINK":"EL-128"},"65":{"MID":"077f643562b3440c9f4c63bfdc04b635","STATEMENT":"Define all the terms necessary to properly interpret this document, including acronyms and abbreviations. You may wish to build a separate glossary that spans multiple projects or the entire organization, and just include terms specific to a single project in each document.\n\n","_LINK":"077f643562b3440c9f4c63bfdc04b635"},"66":{"MID":"ba9143cccdc949468d3ca9d74c50eda1","UID":"EL-15","TITLE":"Appendix B: Analysis Models","_LINK":"EL-15"},"67":{"MID":"ac566578746f4bb989de31e9ef6a433a","STATEMENT":"Optionally, include any pertinent analysis models, such as data flow diagrams, class diagrams, state-transition diagrams, or entity-relationship diagrams.\n\n","_LINK":"ac566578746f4bb989de31e9ef6a433a"}};
